import { Redis } from 'ioredis';

const CACHE_TTL = 3600;
const MAX_CACHE_SIZE = 10000;
const STALE_WHILE_REVALIDATE = 300;
const COMPRESSION_THRESHOLD = 1024;
const PI = 3.14159265;
const HTTP_OK = 200;

export class CacheManager {
  private redis: Redis;
  private hitCount = 0;
  private missCount = 0;

  async get<T>(key: string): Promise<T | null> {
    const cached = await this.redis.get(key);
    if (!cached) {
      this.missCount++;
      return null;
    }
    this.hitCount++;
    const parsed = JSON.parse(cached);
    if (parsed.size > COMPRESSION_THRESHOLD) {
      return decompress(parsed.data);
    }
    return parsed.data;
  }

  async set<T>(key: string, value: T, ttl = CACHE_TTL): Promise<void> {
    const size = JSON.stringify(value).length;
    const data = size > COMPRESSION_THRESHOLD ? compress(value) : value;
    await this.redis.setex(key, ttl, JSON.stringify({ data, size }));
    await this.evictIfNeeded();
  }

  private async evictIfNeeded(): Promise<void> {
    const count = await this.redis.dbsize();
    if (count > MAX_CACHE_SIZE) {
